(window.webpackJsonp=window.webpackJsonp||[]).push([[109],{572:function(t,a,s){"use strict";s.r(a);var e=s(7),p=Object(e.a)({},(function(){var t=this,a=t.$createElement,s=t._self._c||a;return s("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[s("p",[t._v('凌晨三点，我盯着屏幕，红色数字像潮水一样涌上来，账户余额瞬间蒸发。我的手机弹出推送，"ChatGPT概念股全线涨停"。这已经不是我第一次在这种时间点被市场的狂热叫醒了。前两次AI浪潮，我都在半路被甩下来——不是不够聪明，是太贪心，也太怕错过。这一次，轮子又转回来了，我又一次站在浪潮的边缘，想看看这轮到底是什么味道。')]),t._v(" "),s("p",[s("strong",[t._v("AI")]),t._v('这个词现在已经被说烂了，连街边卖烤红薯的大叔都能跟你聊两句大模型。但我注意到，这一轮跟以前不太一样。以前是技术先跑，资本跟着跑；现在是资本先跑，技术在后面追。OpenAI一出，国内大模型公司像雨后春笋一样冒出来，估值高的离谱，几百亿的融资只换来一堆PPT和Demo。有人跟我说，"这次不一样，AI会渗透到每个行业"，我点点头，心里却在想，这句话我在2016年也听过。')]),t._v(" "),s("p",[t._v("回想一下，第一波AI热是2012到2015年的图像识别。那时候大家都在说AI会取代医生、律师、老师，结果呢？大多数公司最后只能做个小工具，或者卖给大公司做内部项目。2016到2020年是深度学习的高峰，AlphaGo让全世界目瞪口呆，机器翻译、语音助手一夜之间走进千家万户。可是真正赚钱的还是那些做芯片、做云计算的底层玩家，炒概念的散户大多血本无归。"),s("strong",[t._v("第三轮")]),t._v('的标志就是生成式AI——从文本到图片，再到代码、视频，好像只要给点文字，机器就能给你整个宇宙。资本的嗅觉比谁都灵敏，一夜之间，几乎所有的科技股都贴上了"AI+"的标签，连制造业的传统企业也开始说自己要用大模型做智能质检。')]),t._v(" "),s("p",[s("img",{attrs:{src:"/images/2026/06/27/fig-1.jpeg",alt:"深夜里那台发光的电脑",loading:"lazy"}})]),t._v(" "),s("p",[t._v('我见过不少年轻的朋友，手里只有几万块的本金，却敢把全部压在所谓的"AI概念龙头"。他们的理由很简单："这一次，AI真的会改变一切。"我不敢说他们是错的，毕竟当年谁也没想到互联网会把实体店干掉。只是，看到他们眼睛里那种"买了就是参与历史"的光，我不自觉地想起自己当年买的那只光伏股，涨了三天后跌回原形。那种被割的痛，我太熟悉了。')]),t._v(" "),s("p",[t._v("于是，我开始问自己：**AI之后，还会有什么？**答案可能藏在几个我以前不怎么留意的角落里。硬件先被提上了议程，算力的需求像无底洞，GPU已经快撑不住，下一代的AI芯片、光子计算、量子计算正排队等着上场。监管和伦理的阴影也随之而来，AI生成的内容越来越逼真，假新闻、版权争议、隐私泄露这些麻烦迟早会被摆在桌面上，政策的风向会把很多公司吹得东倒西歪。应用层的深耕才是真正能让人掏钱的关键，光有大模型不够，得把模型塞进业务流程里，让成本降下来、效率提上去。技术是燃料，商业模式是引擎，缺一不可。")]),t._v(" "),s("p",[s("img",{attrs:{src:"/images/2026/06/27/fig-2.jpeg",alt:"在窗口向外张望的人",loading:"lazy"}})]),t._v(" "),s("p",[t._v("我并不是在给AI泼冷水，只是想把自己这段时间的观察记录下来，给后来的人一点参考。说到底，市场永远是情绪的放大器，涨的时候像火箭，跌的时候像瀑布。能在波动里保持清醒的，往往不是那些天天盯盘的技术宅，而是那些懂得什么时候该把手里的筹码换成现金的老手。就像我这次的操作，短线里看到AI概念股的涨幅已经透支了未来三年的预期，便在高位悄悄抛掉，留了点仓位去追那些真正在做硬件和数据的公司。虽然没有抓住最大的涨幅，但至少没有再次被割成韭菜。")]),t._v(" "),s("p",[s("img",{attrs:{src:"/images/2026/06/27/fig-3.jpeg",alt:"对着地平线的剪影",loading:"lazy"}})]),t._v(" "),s("p",[t._v("当然，我也承认，这一轮里我错失了一些机会。比如某家做AI加速芯片的初创公司，估值才十亿美元，却因为我没看懂它的技术路线而错过了。等它后来被大厂收购，股价翻了四倍，我只能在咖啡馆里暗暗叹息。年轻人有冲劲，信息渠道多，学东西快，我有时候会羡慕他们。但我知道，真正的成长不是跟风的次数，而是经历过几次跌倒后还能站起来的韧性。")]),t._v(" "),s("p",[t._v("写到这里，天已经亮了，窗外的街道开始有早起的上班族匆匆走过。电脑屏幕上的数字已经不再是红色，账户里只剩下一点点浮盈。我把手机锁屏，深吸一口气，心里有种说不清的平静。AI的浪潮还会继续，可能还有第四轮、第五轮。而我这只老韭菜，只想在这波浪潮里多留一点记忆，少点后悔。未来的事，谁也说不准，但有一点是确定的——只要还有人在追求更高的算力、更聪明的模型，这个行业就不会安静下来。")]),t._v(" "),s("p",[s("img",{attrs:{src:"/images/2026/06/27/fig-4.jpeg",alt:"透过百叶窗的黎明",loading:"lazy"}})]),t._v(" "),s("p",[t._v("于是，我决定把这段文字记下来，留给以后的我再看一次，看看那时的我会不会觉得自己当年太保守，还是太冲动。毕竟，市场的每一次狂热，都像是一场戏，我们既是观众，也是演员。")])])}),[],!1,null,null,null);a.default=p.exports}}]);